// Obtener datos de Laravel
const laravelData = $input.first().json;
const userMessage = laravelData.mensaje || laravelData.message || laravelData.pregunta || '';
const userId = laravelData.user_id || laravelData.usuario_id || null;

// Obtener recetas de MySQL
let recetas = $node['MySQL - receta_original con ingredientes'].json;
if (recetas && !Array.isArray(recetas)) {
  recetas = [recetas];
}

// Limpiar recetas que no tienen título (por si acaso)
recetas = recetas.filter(r => r.titulo && r.titulo.trim() !== '');

// Limitar para rendimiento (máximo 30 recetas)
if (recetas.length > 30) {
  recetas = recetas.slice(0, 30);
}

// Mapeo de dificultad para mostrar
const dificultadMap = {
  'easy': 'Fácil',
  'medium': 'Media', 
  'hard': 'Difícil'
};

// Formatear para Gemma 3 (versión simplificada)
const recetasFormateadas = recetas.map(r => ({
  id: r.id_receta,
  titulo: r.titulo,
  ingredientes: r.solo_ingredientes ? r.solo_ingredientes.substring(0, 200) : 'Sin ingredientes especificados',
  dificultad: dificultadMap[r.dificultad] || r.dificultad,
  tiempo: `${r.tiempo_preparacion} ${r.tiempo_preparacion_unidad === 'minutes' ? 'minutos' : 'horas'}`,
  porciones: r.porciones
}));

return { 
  userMessage,
  userId,
  recetas: recetasFormateadas,
  recetasCompletas: recetas
};

