// Extraer ID de respuesta de Ollama
let responseText = '';
const ollamaResponse = $node['Ollama - Seleccionar Receta'].json;

if (ollamaResponse.message?.content) {
  responseText = ollamaResponse.message.content;
} else if (ollamaResponse.response) {
  responseText = ollamaResponse.response;
}

const match = responseText.match(/\d+/);
let selectedId = match ? parseInt(match[0]) : 0;

const recetasCompletas = $node['Procesar Petición Laravel'].json.recetasCompletas;
let recetaSeleccionada = null;

// Buscar por ID exacto
if (selectedId > 0 && Array.isArray(recetasCompletas)) {
  recetaSeleccionada = recetasCompletas.find(r => r.id_receta === selectedId);
}

// Si no encontró por ID, buscar por coincidencia en título o ingredientes
if (!recetaSeleccionada && recetasCompletas.length > 0) {
  const userMsg = $node['Procesar Petición Laravel'].json.userMessage.toLowerCase();
  let mejorPuntaje = 0;

  for (const receta of recetasCompletas) {
    let puntaje = 0;
    const textoCompleto = (receta.titulo + ' ' + (receta.solo_ingredientes || '')).toLowerCase();

    // Dividir mensaje en palabras significativas
    const palabras = userMsg.split(/\s+/).filter(p => p.length > 2);

    for (const palabra of palabras) {
      if (textoCompleto.includes(palabra)) {
        puntaje += palabra.length;
      }
    }

    // Bonus si la palabra está en el título
    const tituloLower = receta.titulo.toLowerCase();
    for (const palabra of palabras) {
      if (tituloLower.includes(palabra)) {
        puntaje += palabra.length * 2;
      }
    }

    if (puntaje > mejorPuntaje && puntaje > 0) {
      mejorPuntaje = puntaje;
      recetaSeleccionada = receta;
      selectedId = receta.id_receta;
    }
  }
}

// Parsear ingredientes de la receta
const parsearIngredientes = (receta) => {
  if (!receta.ingredientes_completos) return [];

  const ingredientesArray = receta.ingredientes_completos.split('|').filter(i => i && i.trim());
  return ingredientesArray.map(ing => {
    // Intentar extraer nombre, cantidad y unidad
    const match = ing.match(/^(.+?)\s*\(([\d.]+)\s*(\w+)\)$/);
    if (match) {
      return {
        nombre: match[1].trim(),
        cantidad: parseFloat(match[2]),
        unidad: match[3]
      };
    }
    return { nombre: ing, cantidad: null, unidad: null };
  });
};

return { 
  recetaSeleccionada, 
  selectedId, 
  ollamaResponse: responseText,
  userId: $node['Procesar Petición Laravel'].json.userId,
  ingredientesParseados: recetaSeleccionada ? parsearIngredientes(recetaSeleccionada) : []
};

